// IsEmojiPresentation reports whether r is in the wide-2 emoji set
// (see emojiPresentationRanges for the source criteria).
func IsEmojiPresentation(r rune) bool {
	lo, hi := 0, len(emojiPresentationRanges)-1
	for lo <= hi {
		mid := (lo + hi) / 2
		rg := emojiPresentationRanges[mid]
		switch {
		case r < rg[0]:
			hi = mid - 1
		case r > rg[1]:
			lo = mid + 1
		default:
			return true
		}
	}
	return false
}
